import React, { useState, useEffect } from 'react';
   import { v4 as uuidv4 } from 'uuid';

   const App = () => {
   const [rooms, setRooms] = useState([{ id: uuidv4(), messages: [] }]);
   const [activeRoom, setActiveRoom] = useState(rooms[0].id);
   const [username, setUsername] = useState('');

   useEffect(() => {
   const interval = setInterval(() => {
   const newMessage = { id: uuidv4(), text: `New message from ${username}` };
   const activeRoomIndex = rooms.findIndex(room => room.id === activeRoom);
   if (activeRoomIndex !== -1) {
   rooms[activeRoomIndex].messages.push(newMessage);
   }
   setRooms([...rooms]);
   }, 1000);
   return () => clearInterval(interval);
   }, []);

   const handleSendMessage = (room) => {
   const newMessage = { id: uuidv4(), text: `Message from ${username}` };
   const activeRoomIndex = rooms.findIndex(r => r.id === room);
   if (activeRoomIndex !== -1) {
   rooms[activeRoomIndex].messages.push(newMessage);
   }
   setRooms([...rooms]);
   };

   return (
   <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
   <div className="flex items-center justify-between w-full">
   <input
   type="text"
   value={username}
   onChange={e => setUsername(e.target.value)}
   className="p-2 rounded-lg outline-none text-white border-2 border-[#B7D7CD] w-full sm:w-1/2"
   />
   <button
   className="bg-[#C06C88] text-white px-4 rounded-lg hover:bg-[#C06C88] hover:scale-110 active:bg-[#C06C88] active:scale-95 transition-all duration-300"
   onClick={() => handleSendMessage(activeRoom)}
   >
   Send
   </button>
   </div>
   <div className="flex flex-col justify-between w-full sm:w-1/2">
   <div className="flex items-center justify-between w-full">
   <button
   className="bg-[#C06C88] text-white px-4 rounded-lg hover:bg-[#C06C88] hover:scale-110 active:bg-[#C06C88] active:scale-95 transition-all duration-300"
   onClick={() => setActiveRoom(rooms[0].id)}
   >
   Room 1
   </button>
   <button
   className="bg-[#C06C88] text-white px-4 rounded-lg hover:bg-[#C06C88] hover:scale-110 active:bg-[#C06C88] active:scale-95 transition-all duration-300"
   onClick={() => setActiveRoom(rooms[1].id)}
   >
   Room 2
   </button>
   </div>
   <div className="flex flex-col justify-between w-full">
   {rooms.map(room => (
   <div key={room.id} className="bg-[#B7D7CD] p-4 w-full sm:w-1/2">
   <h2 className="text-lg font-bold mb-2">{room.id}</h2>
   {room.messages.map(message => (
   <div key={message.id} className="bg-[#E8E8E8] p-2 mb-2">
   <p className="text-sm">{message.text}</p>
   </div>
   ))}
   </div>
   ))}
   </div>
   </div>
   </div>
   );
   };

   export default App;
